interviewQuestions.answer:
The Temporal Dead Zone is the period between entering a scope (where a let/const variable is hoisted) and the actual declaration of that variable. During the TDZ, the variable exists in the scope but cannot be accessed. Any attempt to read or write the variable throws a ReferenceError. <strong>Example:</strong><br/><br/><pre><code>{
  console.log(x); // ReferenceError: Cannot access 'x' before initialization
  let x = 10;
}</code></pre>

Function declarations are <strong>fully hoisted</strong> -- you can call them before their definition. Function expressions follow the hoisting rules of their assignment keyword. <strong>Example:</strong><br/><br/><pre><code>foo(); // Works: 'foo function'
bar(); // TypeError: bar is not a function (var is undefined)
baz(); // ReferenceError: TDZ

function foo() { console.log('foo function'); }
var bar = function() { console.log('bar function'); };
const baz = function() { console.log('baz function'); };</code></pre>

Output: <strong>undefined</strong>. Inside test(), the <code>var x</code> declaration is hoisted to the top of the function scope. The local x shadows the global x. The code is interpreted as:<br/><br/><pre><code>var x = 10;
function test() {
  var x; // hoisted, initialized to undefined
  console.log(x); // undefined
  x = 20;
}
test();</code></pre>

IIFEs create a new function scope. Any var declarations inside the IIFE are hoisted to the top of the IIFE's scope, not the outer scope. Let/const declarations are hoisted to the block scope of the IIFE body (in TDZ until declaration). <strong>Example:</strong><br/><br/><pre><code>(function() {
  console.log(x); // undefined (var hoisted)
  var x = 5;
})();

console.log(typeof x); // 'undefined' -- x not accessible outside</code></pre>

codeExamples.code:
function hoistingExample() {
  console.log(message); // undefined -- not ReferenceError!
  var message = 'Hello';
  console.log(message); // 'Hello'

  // The above is interpreted as:
  // var message;
  // console.log(message); // undefined
  // message = 'Hello';
  // console.log(message); // 'Hello'
}

hoistingExample();

function tdzExample() {
  // console.log(x); // Would throw ReferenceError (TDZ)
  let x = 10;
  console.log(x); // 10

  {
    // console.log(y); // Would throw ReferenceError (TDZ)
    const y = 20;
    console.log(y); // 20
    // y = 30; // TypeError: Assignment to constant variable
  }

  // console.log(y); // ReferenceError: y is not defined (block scoped)
}

tdzExample();

// Function Declaration -- fully hoisted
sayHello(); // 'Hello!'

function sayHello() {
  console.log('Hello!');
}

// Function Expression -- only variable is hoisted
// sayGoodbye(); // TypeError: sayGoodbye is not a function

var sayGoodbye = function() {
  console.log('Goodbye!');
};

sayGoodbye(); // 'Goodbye!' (works after assignment)

// Arrow Function Expression
// greet(); // ReferenceError: TDZ (const)
const greet = () => console.log('Hi!');
greet(); // 'Hi!'

// var -- shares one binding across all iterations
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log('var:', i), 100);
}
// Output: var: 3, var: 3, var: 3

// let -- creates a new binding per iteration
for (let j = 0; j < 3; j++) {
  setTimeout(() => console.log('let:', j), 100);
}
// Output: let: 0, let: 1, let: 2

// const -- also block-scoped, but can't increment
// for (const k = 0; k < 3; k++) {} // TypeError: Assignment to constant

// With const + for...of:
const items = ['a', 'b', 'c'];
for (const item of items) {
  console.log(item); // 'a', 'b', 'c' (new binding each iteration)
}

// typeof before declaration -- tricky!
console.log(typeof myVar); // 'undefined' (var hoisted)
console.log(typeof myLet); // 'undefined' (not ReferenceError!)
console.log(typeof myFunc); // 'function' (fully hoisted)
// console.log(typeof MyClass); // ReferenceError: TDZ

var myVar = 1;
let myLet = 2;
function myFunc() {}
class MyClass {}

// Edge: typeof on undeclared variable returns 'undefined'
// But accessing an undeclared variable throws ReferenceError
// console.log(nonexistent); // ReferenceError
console.log(typeof nonexistent); // 'undefined' (safe check)

// Class expression with const
const User = class {
  constructor(name) { this.name = name; }
};
const user = new User('Alice');
console.log(user.name); // 'Alice'
